interface Edict {
  v: {
    velocity: [number, number, number];
    origin: [number, number, number];
    classname: string;
    flags: number;
    movetype: number;
    nextthink: number;
  };
  free: boolean;
}

function svRunThink(ent: Edict): boolean {
  const thinktime = ent.v.nextthink;
  if (thinktime <= 0 || thinktime > sv_time + host_frametime) return true;
  ent.v.nextthink = 0;
  prExecuteProgram(ent.v.think);
  return !ent.free;
}
